- plugins/slack/src/slack-api.ts

Context:
The Slack plugin has two patterns to migrate:

1. `waitForSlackAuth()` at lines 326-343 uses manual setInterval polling:
```typescript
export const waitForSlackAuth = (): Promise<boolean> =>
  new Promise(resolve => {
    let elapsed = 0;
    const interval = 500;
    const maxWait = 3000;
    const timer = setInterval(() => {
      elapsed += interval;
      if (isSlackAuthenticated()) {
        clearInterval(timer);
        resolve(true);
        return;
      }
      if (elapsed >= maxWait) {
        clearInterval(timer);
        resolve(false);
      }
    }, interval);
  });
```

Replace with:
```typescript
import { waitUntil, getLocalStorage } from '@opentabs-dev/plugin-sdk';

export const waitForSlackAuth = async (): Promise<boolean> => {
  try {
    await waitUntil(() => isSlackAuthenticated(), { interval: 500, timeout: 3000 });
    return true;
  } catch {
    return false;
  }
};
```

2. Direct `localStorage.getItem()` calls (around lines 39-40 and 232-248) should use `getLocalStorage()` instead. Search for all `localStorage.getItem` and `localStorage.key` and `localStorage.length` usages.

Constraints:
- Do NOT change isSlackAuthenticated() or any of the token extraction logic — only the polling wrapper and localStorage access
- Do NOT change slackApi() or any tool files
- The waitUntil timeout must be 3000 (Slack uses 3s, not the standard 5s used by other plugins)
- Keep the same return type: Promise<boolean>
